                {"speaker": "You", "swissGerman": "Herzliche Glückwunsch! Mir sind so stolz uf dich!", "german": "Herzlichen Glückwunsch! Wir sind so stolz auf dich!", "english": "Congratulations! We're so proud of you!", "spanish": "¡Enhorabuena! ¡Estamos muy orgullosos/as de ti!"},
                {"speaker": "Child", "swissGerman": "Merci! Am Fritig isch d'Maturfäier im Kongresshuus.", "german": "Danke! Am Freitag ist die Maturafeier im Kongresshaus.", "english": "Thanks! On Friday is the Matura ceremony at the congress hall.", "spanish": "¡Gracias! El viernes es la ceremonia del bachillerato en el palacio de congresos."},
                {"speaker": "You", "swissGerman": "Wunderbar! Und wie fiiret ihr nachher?", "german": "Wunderbar! Und wie feiert ihr nachher?", "english": "Wonderful! And how do you celebrate afterwards?", "spanish": "¡Maravilloso! ¿Y cómo lo celebras después?"},
